import{_ as r,c as a}from"./app.f21a7cce.js";const p={},i=a('<h1 id="\u5982\u4F55\u9605\u8BFB\u4E00\u672C\u4E66" tabindex="-1"><a class="header-anchor" href="#\u5982\u4F55\u9605\u8BFB\u4E00\u672C\u4E66" aria-hidden="true">#</a> \u5982\u4F55\u9605\u8BFB\u4E00\u672C\u4E66</h1><h2 id="\u7B2C\u4E00\u7AE0-\u9605\u8BFB\u7684\u6D3B\u529B\u548C\u827A\u672F" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u4E00\u7AE0-\u9605\u8BFB\u7684\u6D3B\u529B\u548C\u827A\u672F" aria-hidden="true">#</a> \u7B2C\u4E00\u7AE0 \u9605\u8BFB\u7684\u6D3B\u529B\u548C\u827A\u672F</h2><h3 id="\u4E3B\u52A8\u9605\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u4E3B\u52A8\u9605\u8BFB" aria-hidden="true">#</a> \u4E3B\u52A8\u9605\u8BFB</h3><p><strong>\u9605\u8BFB\u7684\u827A\u672F\u4E5F\u5728\u5C3D\u53EF\u80FD\u638C\u63E1\u4F4F\u6BCF\u4E00\u79CD\u8BAF\u606F\u7684\u6280\u5DE7\u3002</strong></p><p><strong>\u9605\u8BFB\u7684\u76EE\u6807\uFF1B\u4E3A\u83B7\u5F97\u54A8\u8BE2\u800C\u8BFB\uFF0C\u4EE5\u53CA\u4E3A\u6C42\u5F97\u7406\u89E3\u800C\u8BFB\u3002</strong></p><p>\u5C06\u9605\u8BFB\u533A\u5206\u6210\u4E24\u79CD\u4E0D\u540C\u7684\u610F\u4E49</p><ul><li>\u7B2C\u4E00\u79CD\u610F\u4E49\u662F\u6211\u4EEC\u81EA\u5DF1\u5728\u9605\u8BFB\u62A5\u7EB8\u3001\u6742\u5FD7\u3001\u6216\u5176\u4ED6\u7684\u4E1C\u897F\u65F6\uFF0C\u51ED\u6211\u4EEC\u7684\u9605\u8BFB\u6280\u5DE7\u4E0E\u806A\u660E\u624D\u667A\uFF0C\u4E00\u4E0B\u5B50\u4FBF\u80FD\u878D\u4F1A\u8D2F\u901A\u4E86\u3002\u8FD9\u6837\u7684\u8BFB\u7269\u80FD\u589E\u52A0\u6211\u4EEC\u7684\u8D44\u8BAF\uFF0C\u5374\u4E0D\u80FD\u589E\u8FDB\u6211\u4EEC\u7684\u7406\u89E3\u529B\uFF0C\u56E0\u4E3A\u5728\u5F00\u59CB\u9605\u8BFB\u4E4B\u524D\uFF0C\u6211\u4EEC\u7684\u7406\u89E3\u529B\u5C31\u5DF2\u7ECF\u4E0E\u4ED6\u4EEC\u5B8C\u5168\u76F8\u5F53\u4E86\u3002</li><li>\u7B2C\u4E8C\u79CD\u610F\u4E49\u662F\u4E00\u4E2A\u4EBA\u8BD5\u7740\u8BFB\u67D0\u6837\u4ED6\u4E00\u5F00\u59CB\u5E76\u4E0D\u600E\u4E48\u4E86\u89E3\u7684\u4E1C\u897F\u3002\u8FD9\u4E2A\u4E1C\u897F\u7684\u6C34\u5E73\u5C31\u662F\u6BD4\u9605\u8BFB\u7684\u4EBA\u9AD8\u4E0A\u4E00\u622A\u3002\u8FD9\u4E2A\u4F5C\u8005\u8981\u8868\u8FBE\u7684\u4E1C\u897F\uFF0C\u80FD\u589E\u8FDB\u9605\u8BFB\u8005\u7684\u7406\u89E3\u529B\u3002\u8FD9\u79CD\u53CC\u65B9\u6C34\u51C6\u4E0D\u9F50\u4E4B\u4E0B\u7684\u6C9F\u901A\uFF0C\u53EF\u4EE5\u7406\u89E3\u5230\u66F4\u591A\u7684\u4E1C\u897F\u4E86\u3002</li></ul><p>\u5728\u4EC0\u4E48\u6837\u7684\u72B6\u51B5\u4E0B\uFF0C\u6211\u4EEC\u4F1A\u4E3A\u4E86\u589E\u8FDB\u7406\u89E3\u800C\u9605\u8BFB\uFF1F</p><ul><li>\u4E00\u5F00\u59CB\u65F6\u4E0D\u76F8\u7B49\u7684\u7406\u89E3\u7A0B\u5EA6\u3002</li><li>\u9605\u8BFB\u7684\u4EBA\u4E00\u5B9A\u8981\u628A\u4E0D\u76F8\u7B49\u7684\u7406\u89E3\u529B\u514B\u670D\u5230\u4E00\u5B9A\u7A0B\u5EA6\u4E4B\u5185\u3002</li></ul><p><strong>\u9605\u8BFB\u5C31\u662F\u5B66\u4E60\uFF1A\u6307\u5BFC\u578B\u7684\u5B66\u4E60\uFF0C\u4EE5\u53CA\u81EA\u6211\u53D1\u73B0\u578B\u7684\u5B66\u4E60\u4E4B\u95F4\u7684\u5DEE\u5F02</strong></p><p>\u8981\u53BB\u7406\u89E3\uFF0C\u8981\u88AB\u542F\u53D1\uFF0C\u9664\u4E86\u77E5\u9053\u4F5C\u8005\u8BF4\u7684\u8BDD\u4E4B\u5916\uFF0C\u8FD8\u8981\u660E\u767D\u4ED6\u7684\u610F\u601D\uFF0C\u61C2\u5F97\u4ED6\u4E3A\u4EC0\u4E48\u4F1A\u8FD9\u4E48\u8BF4\u3002 \u8499\u7530\u8BF4\uFF1A\u201C\u521D\u5B66\u8005\u7684\u65E0\u77E5\u5728\u4E8E\u672A\u5B66\uFF0C\u800C\u5B66\u8005\u7684\u65E0\u77E5\u5728\u4E8E\u5B66\u540E\u201D\u3002</p><p><strong>\u8001\u5E08\u7684\u51FA\u5E2D\u4E0E\u7F3A\u5E2D</strong></p><p>\u9605\u8BFB\uFF0C\u5C31\u50CF\u662F\u975E\u8F85\u52A9\u578B\u7684\u81EA\u6211\u53D1\u73B0\u5B66\u4E60\uFF0C\u662F\u8DDF\u7740\u4E00\u4F4D\u7F3A\u5E2D\u7684\u8001\u5E08\u5728\u5B66\u4E60\u3002</p><h2 id="\u7B2C\u4E8C\u7AE0-\u9605\u8BFB\u7684\u5C42\u6B21" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u4E8C\u7AE0-\u9605\u8BFB\u7684\u5C42\u6B21" aria-hidden="true">#</a> \u7B2C\u4E8C\u7AE0 \u9605\u8BFB\u7684\u5C42\u6B21</h2><ul><li>\u7B2C\u4E00\u5C42\u6B21\u7684\u9605\u8BFB\uFF1A\u57FA\u7840\u9605\u8BFB\uFF08elementary reading\uFF09 \u5728\u8FD9\u4E2A\u5C42\u6B21\u7684\u9605\u8BFB\u4E2D\uFF0C\u8981\u95EE\u8BFB\u8005\u7684\u95EE\u9898\u662F\uFF1A\u201C\u8FD9\u4E2A\u53E5\u5B50\u5728\u8BF4\u4EC0\u4E48\uFF1F\u201D</li><li>\u7B2C\u4E8C\u5C42\u6B21\u7684\u9605\u8BFB\uFF1A\u68C0\u89C6\u9605\u8BFB\uFF08inspectional reading\uFF09 \u68C0\u89C6\u9605\u8BFB\u662F\u7CFB\u7EDF\u5316\u7565\u8BFB\uFF08skimming systematically\uFF09\u7684\u4E00\u95E8\u827A\u672F\u3002 \u4F60\u7684\u76EE\u6807\u662F\u4ECE\u8868\u9762\u53BB\u89C2\u5BDF\u8FD9\u672C\u4E66\uFF0C\u5B66\u4E60\u5230\u5149\u662F\u4E66\u7684\u8868\u9762\u6240\u6559\u7ED9\u4F60\u7684\u4E00\u5207\u3002 \u8FD9\u4E2A\u5C42\u6B21\u7684\u9605\u8BFB\u4E2D\uFF0C\u8981\u95EE\u8BFB\u8005\u7684\u95EE\u9898\u662F\uFF1A\u201C\u8FD9\u672C\u4E66\u5728\u8C08\u4EC0\u4E48\uFF1F\u201D</li><li>\u7B2C\u4E09\u5C42\u6B21\u7684\u9605\u8BFB\uFF1A\u5206\u6790\u9605\u8BFB\uFF08analytical reading\uFF09 \u5168\u76D8\u7684\u9605\u8BFB\uFF0C\u5B8C\u6574\u7684\u9605\u8BFB\uFF0C\u4F18\u8D28\u7684\u9605\u8BFB\u3002 \u6293\u4F4F\u4E00\u672C\u4E66\uFF0C\u4E00\u76F4\u8981\u8BFB\u5230\u8FD9\u672C\u4E66\u6210\u4E3A\u4ED6\u81EA\u5DF1\u4E3A\u6B62\u3002 \u5F17\u5170\u897F\u65AF\xB7\u57F9\u6839\u66FE\u8BF4\u8FC7\uFF1A\u201C\u6709\u4E9B\u4E66\u53EF\u4EE5\u6D45\u5C1D\u8F84\u6B62\uFF0C\u6709\u4E9B\u4E66\u9700\u8981\u751F\u541E\u6D3B\u5265\uFF0C\u53EA\u6709\u5C11\u6570\u7684\u4E66\u662F\u8981\u5480\u56BC\u4E0E\u6D88\u5316\u7684\u201D</li><li>\u7B2C\u56DB\u5C42\u6B21\u7684\u9605\u8BFB\uFF0C\u4E3B\u9898\u9605\u8BFB\uFF08syntopical reading\uFF09 / \u6BD4\u8F83\u9605\u8BFB\uFF08comparative reading\uFF09 \u5728\u505A\u4E3B\u9898\u9605\u8BFB\u65F6\uFF0C\u9605\u8BFB\u8005\u4F1A\u8BFB\u5F88\u591A\u4E66\uFF0C\u800C\u4E0D\u662F\u4E00\u672C\u4E66\uFF0C\u5E76\u5217\u4E3E\u51FA\u8FD9\u4E9B\u4E66\u4E4B\u95F4\u76F8\u4E92\u4E4B\u5904\uFF0C\u63D0\u51FA\u4E00\u4E2A\u6240\u6709\u4E66\u90FD\u8C08\u5230\u7684\u4E3B\u9898\u3002\u4E3B\u9898\u9605\u8BFB\u8005\u8981\u67B6\u6784\u51FA\u4E00\u4E2A\u53EF\u80FD\u5728\u54EA\u4E00\u672C\u4E66\u90FD\u6CA1\u63D0\u5230\u8FC7\u7684\u4E3B\u9898\u5206\u6790\u3002</li></ul><h2 id="\u7B2C\u4E09\u7AE0-\u9605\u8BFB\u7684\u7B2C\u4E00\u4E2A\u5C42\u6B21-\u57FA\u7840\u9605\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u4E09\u7AE0-\u9605\u8BFB\u7684\u7B2C\u4E00\u4E2A\u5C42\u6B21-\u57FA\u7840\u9605\u8BFB" aria-hidden="true">#</a> \u7B2C\u4E09\u7AE0 \u9605\u8BFB\u7684\u7B2C\u4E00\u4E2A\u5C42\u6B21\uFF1A\u57FA\u7840\u9605\u8BFB</h2><p>\u5B66\u4E60\u9605\u8BFB\u7684\u9636\u6BB5</p><p>\u9605\u8BFB\u7684\u9636\u6BB5\u548C\u5C42\u6B21</p><p>\u66F4\u9AD8\u5C42\u6B21\u7684\u9605\u8BFB\u548C\u9AD8\u7B49\u6559\u80B2</p><p>\u9605\u8BFB\u4E0E\u6C11\u4E3B\u6559\u80B2\u7684\u7406\u5FF5</p><h2 id="\u7B2C\u56DB\u7AE0-\u9605\u8BFB\u7684\u7B2C\u4E8C\u4E2A\u5C42\u6B21-\u68C0\u89C6\u9605\u8BFB" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u56DB\u7AE0-\u9605\u8BFB\u7684\u7B2C\u4E8C\u4E2A\u5C42\u6B21-\u68C0\u89C6\u9605\u8BFB" aria-hidden="true">#</a> \u7B2C\u56DB\u7AE0 \u9605\u8BFB\u7684\u7B2C\u4E8C\u4E2A\u5C42\u6B21\uFF1A\u68C0\u89C6\u9605\u8BFB</h2><p><strong>\u68C0\u89C6\u9605\u8BFB\u4E00\uFF1A\u6709\u7CFB\u7EDF\u5730\u7565\u8BFB\u6216\u7C97\u8BFB</strong></p><p>\u7B2C\u4E00\uFF0C\u4F60\u5E76\u4E0D\u77E5\u9053\u81EA\u5DF1\u60F3\u4E0D\u60F3\u8BFB\u8FD9\u672C\u4E66\u3002\u4F60\u4E5F\u4E0D\u77E5\u9053\u8FD9\u672C\u4E66\u662F\u5426\u503C\u5F97\u505A\u5206\u6790\u9605\u8BFB\u3002\u4F46\u4F60\u89C9\u5F97\uFF0C\u6216\u53EA\u8981\u4F60\u80FD\u6316\u6398\u51FA\u6765\uFF0C\u4E66\u4E2D\u7684\u8D44\u8BAF\u53CA\u89C2\u70B9\u5C31\u8D77\u7801\u4F1A\u5BF9\u4F60\u6709\u7528\u3002</p><p>\u5176\u6B21\uFF0C\u4F60\u60F3\u8981\u53D1\u6398\u6240\u6709\u7684\u4E1C\u897F\uFF0C\u4F46\u65F6\u95F4\u5F88\u6709\u9650\u3002</p><p>\u5982\u4F55\u7565\u8BFB\uFF1A</p><ol><li><p>\u5148\u770B\u4E66\u540D\u9875\uFF0C\u6709\u5E8F\u5C31\u5148\u770B\u5E8F\uFF0C\u8981\u5F88\u5FEB\u7684\u770B\u8FC7\u53BB\u3002\u7279\u522B\u8981\u6CE8\u610F\u526F\u6807\u9898\uFF0C\u6216\u5176\u4ED6\u7684\u76F8\u5173\u8BF4\u660E\u548C\u5B97\u65E8\uFF0C\u6216\u8005\u4F5C\u8005\u5199\u4F5C\u672C\u4E66\u7684\u7279\u6B8A\u89D2\u5EA6\u3002\u5728\u5B8C\u6210\u8FD9\u4E2A\u6B65\u9AA4\u4E4B\u524D\uFF0C\u4F60\u5BF9\u8FD9\u672C\u4E66\u7684\u4E3B\u9898\u5DF2\u7ECF\u6709\u6982\u5FF5\u4E86\u3002</p></li><li><p>\u7814\u7A76\u76EE\u5F55\u9875\uFF0C\u5BF9\u8FD9\u672C\u4E66\u7684\u57FA\u672C\u67B6\u6784\u505A\u6982\u62EC\u6027\u7684\u7406\u89E3\u3002</p></li><li><p>\u5982\u679C\u4E66\u4E2D\u9644\u6709\u7D22\u5F15\uFF0C\u4E5F\u8981\u68C0\u9605\u4E00\u4E0B\u3002\u5FEB\u901F\u8BC4\u4F30\u4E00\u4E0B\u8FD9\u672C\u4E66\u6DB5\u76D6\u4E86\u54EA\u4E9B\u8BAE\u9898\u7684\u8303\u56F4\uFF0C\u4EE5\u53CA\u6240\u63D0\u5230\u7684\u4E66\u7C4D\u79CD\u7C7B\u4E0E\u4F5C\u8005\u7B49\u7B49\u3002\u5982\u679C\u4F60\u53D1\u73B0\u5217\u4E3E\u51FA\u6765\u7684\u54EA\u4E00\u6761\u8BCD\u6C47\u5F88\u91CD\u8981\uFF0C\u81F3\u5C11\u8981\u770B\u4E00\u4E0B\u5F15\u7528\u5230\u8FD9\u4E2A\u8BCD\u76EE\u7684\u67D0\u51E0\u9875\u5185\u6587\u3002</p></li><li><p>\u5982\u679C\u90A3\u662F\u4E00\u672C\u5305\u7740\u4E66\u8863\u7684\u65B0\u4E66\uFF0C\u4E0D\u59A8\u8BFB\u4E00\u4E0B\u51FA\u7248\u8005\u7684\u4ECB\u7ECD\u3002</p></li><li><p>\u4ECE\u4F60\u5BF9\u4E00\u672C\u4E66\u7684\u76EE\u5F55\u5F88\u6982\u7565\uFF0C\u751A\u81F3\u6709\u70B9\u6A21\u7CCA\u7684\u5370\u8C61\u5F53\u4E2D\uFF0C\u5F00\u59CB\u6311\u51E0\u4E2A\u770B\u6765\u8DDF\u4E3B\u9898\u606F\u606F\u76F8\u5173\u7684\u7BC7\u7AE0\u6765\u770B\u3002\u5982\u679C\u8FD9\u4E9B\u7BC7\u7AE0\u5728\u5F00\u5934\u6216\u7ED3\u5C3E\u6709\u6458\u8981\u8BF4\u660E\uFF0C\u5C31\u8981\u4ED4\u7EC6\u5730\u9605\u8BFB\u8FD9\u4E9B\u8BF4\u660E\u3002</p></li><li><p>\u6700\u540E\u4E00\u6B65\uFF0C\u628A\u4E66\u6253\u5F00\uFF0C\u4E1C\u7FFB\u7FFB\u897F\u7FFB\u7FFB\uFF0C\u5FF5\u4E2A\u4E00\u4E24\u6BB5\uFF0C\u6709\u65F6\u5019\u8FDE\u7EED\u8BFB\u51E0\u9875\uFF0C\u4E0D\u8981\u592A\u591A\u3002\u7528\u8FD9\u79CD\u65B9\u6CD5\u628A\u5168\u4E66\u7FFB\u4E00\u904D\uFF0C\u968F\u65F6\u5BFB\u627E\u4E3B\u8981\u8BBA\u70B9\u7684\u8BAF\u53F7\uFF0C\u7559\u610F\u4E3B\u9898\u7684\u8109\u7EDC\u3002\u6700\u91CD\u8981\u7684\u662F\u4E0D\u8981\u5FFD\u7565\u6700\u540E\u7684\u4E24\u4E09\u9875\u3002</p></li></ol><p>\u4F60\u53EF\u4EE5\u628A\u81EA\u5DF1\u60F3\u6210\u662F\u4E00\u4E2A\u4FA6\u63A2\uFF0C\u5728\u627E\u5BFB\u4E00\u672C\u4E66\u7684\u4E3B\u9898\u6216\u601D\u60F3\u7684\u7EBF\u7D22\u3002\u968F\u65F6\u4FDD\u6301\u654F\u611F\uFF0C\u5C31\u5F88\u5BB9\u6613\u8BA9\u4E00\u5207\u72B6\u51B5\u6E05\u695A\u3002</p><p><strong>\u68C0\u89C6\u9605\u8BFB\u4E8C\uFF1A\u7C97\u6D45\u7684\u9605\u8BFB</strong></p><p>\u5934\u4E00\u6B21\u9762\u5BF9\u4E00\u672C\u96BE\u8BFB\u7684\u4E66\u7684\u65F6\u5019\uFF0C\u4ECE\u5934\u5230\u5C3E\u5148\u8BFB\u5B8C\u4E00\u904D\uFF0C\u78B0\u5230\u4E0D\u61C2\u7684\u5730\u65B9<strong>\u4E0D\u8981</strong>\u505C\u4E0B\u6765\u67E5\u8BE2\u6216\u601D\u7D22\u3002</p><p>\u53EA\u6CE8\u610F\u4F60\u80FD\u7406\u89E3\u7684\u90E8\u5206\uFF0C\u4E0D\u8981\u4E3A\u4E00\u4E9B\u6CA1\u6CD5\u7ACB\u5373\u4E86\u89E3\u7684\u4E1C\u897F\u800C\u505C\u987F\u3002\u7EE7\u7EED\u8BFB\u4E0B\u53BB\uFF0C\u7565\u8FC7\u90A3\u4E9B\u4E0D\u61C2\u7684\u90E8\u5206\uFF0C\u5F88\u5FEB\u4F60\u4F1A\u8BFB\u5230\u4F60\u770B\u5F97\u61C2\u7684\u5730\u65B9\u3002\u96C6\u4E2D\u7CBE\u795E\u5728\u8FD9\u4E2A\u90E8\u5206\u3002\u7EE7\u7EED\u8FD9\u6837\u8BFB\u4E0B\u53BB\u3002\u5C06\u5168\u4E66\u8BFB\u5B8C\uFF0C\u4E0D\u8981\u88AB\u4E00\u4E2A\u770B\u4E0D\u61C2\u7684\u7AE0\u8282\u3001\u6CE8\u89E3\u3001\u8BC4\u8BBA\u6216\u53C2\u8003\u8D44\u6599\u963B\u6320\u6216\u6CC4\u6C14\u3002\u5982\u679C\u4F60\u8BA9\u81EA\u5DF1\u88AB\u56F0\u4F4F\u4E86\uFF0C\u5982\u679C\u4F60\u5BB9\u8BB8\u81EA\u5DF1\u88AB\u67D0\u4E2A\u987D\u56FA\u7684\u6BB5\u843D\u7ED1\u4F4F\u4E86\uFF0C\u4F60\u5C31\u662F\u88AB\u6253\u8D25\u4E86\u3002\u5728\u5927\u591A\u6570\u60C5\u51B5\u91CC\uFF0C\u4F60\u4E00\u65E6\u548C\u5B83\u7EA0\u7F20\uFF0C\u5C31\u5F88\u96BE\u8131\u56F0\u800C\u51FA\u3002\u5728\u8BFB\u7B2C\u4E8C\u904D\u7684\u65F6\u5019\uFF0C\u4F60\u5BF9\u90A3\u4E2A\u5730\u65B9\u7684\u4E86\u89E3\u53EF\u80FD\u4F1A\u591A\u4E00\u4E9B\uFF0C\u4F46\u662F\u5728\u90A3\u4E4B\u524D\uFF0C\u4F60\u5FC5\u987B\u81F3\u5C11\u5C06\u8FD9\u672C\u4E66\u5148\u4ECE\u5934\u5230\u5C3E\u8BFB\u4E00\u904D\u624D\u884C\u3002</p><p>\u4F60\u4ECE\u5934\u5230\u5C3E\u8BFB\u4E86\u4E00\u904D\u4E4B\u540E\u7684\u4E86\u89E3\u2014\u2014\u5C31\u7B97\u53EA\u6709 50%\u6216\u66F4\u5C11\u2014\u2014\u80FD\u5E2E\u52A9\u4F60\u5728\u540E\u6765\u91CD\u8BFB\u7B2C\u4E00\u6B21\u7565\u8FC7\u7684\u90E8\u5206\u65F6\uFF0C\u589E\u8FDB\u7406\u89E3\u3002\u5C31\u7B97\u4F60\u4E0D\u91CD\u8BFB\uFF0C\u5BF9\u4E00\u672C\u96BE\u5EA6\u5F88\u9AD8\u7684\u4E66\u4E86\u89E3\u4E86\u4E00\u534A\uFF0C\u4E5F\u6BD4\u4EC0\u4E48\u90FD\u4E0D\u4E86\u89E3\u6765\u5F97\u8981\u597D\u4E9B\u2014\u2014\u5982\u679C\u4F60\u8BA9\u81EA\u5DF1\u5728\u4E00\u78B0\u4E0A\u56F0\u96BE\u7684\u5730\u65B9\u5C31\u505C\u4F4F\uFF0C\u6700\u540E\u5C31\u53EF\u80FD\u5BF9\u8FD9\u672C\u4E66\u771F\u7684\u4E00\u65E0\u6240\u77E5\u4E86\u3002</p><p><strong>\u9605\u8BFB\u7684\u901F\u5EA6</strong></p><p><strong>\u9017\u7559\u4E0E\u5012\u9000</strong></p><p><strong>\u7406\u89E3\u7684\u95EE\u9898</strong></p><p>\u4E13\u5FC3\u4E00\u81F4\u4E5F\u5C31\u662F\u4E3B\u52A8\u9605\u8BFB\u7684\u53E6\u4E00\u79CD\u79F0\u547C\u3002</p><p><strong>\u68C0\u89C6\u9605\u8BFB\u7684\u6458\u8981</strong></p><p>\u7565\u8BFB\u6216\u7C97\u8BFB\u4E00\u672C\u4E66\u603B\u662F\u4E2A\u597D\u4E3B\u610F\u3002\u5C24\u5176\u5F53\u4F60\u5E76\u4E0D\u6E05\u695A\u624B\u8FB9\u7684\u4E00\u672C\u4E66\u662F\u5426\u503C\u5F97\u7EC6\u5FC3\u9605\u8BFB\u65F6\uFF08\u7ECF\u5E38\u53D1\u751F\u8FD9\u79CD\u60C5\u51B5\uFF09\uFF0C\u5FC5\u987B\u5148\u7565\u8BFB\u4E00\u4E0B\u3002\u7565\u8BFB\u8FC7\u540E\uFF0C\u4F60\u5C31\u4F1A\u5F88\u6E05\u695A\u4E86\u3002\u4E00\u822C\u6765\u8BF4\uFF0C\u5C31\u7B97\u4F60\u60F3\u8981\u4ED4\u7EC6\u9605\u8BFB\u7684\u4E66\u4E5F\u8981\u5148\u7565\u8BFB\u4E00\u4E0B\uFF0C\u4ECE\u57FA\u672C\u67B6\u6784\u4E0A\u5148\u627E\u5230\u4E00\u4E9B\u60F3\u6CD5\u3002\u6700\u540E\uFF0C\u5728\u7B2C\u4E00\u6B21\u9605\u8BFB\u4E00\u672C\u96BE\u8BFB\u7684\u4E66\u65F6\uFF0C\u4E0D\u8981\u4F01\u56FE\u4E86\u89E3\u6BCF\u4E00\u4E2A\u5B57\u53E5\u3002\u8FD9\u662F\u6700\u6700\u91CD\u8981\u7684\u4E00\u4E2A\u89C4\u5219\u3002\u8FD9\u4E5F\u662F\u68C0\u89C6\u9605\u8BFB\u7684\u57FA\u672C\u6982\u5FF5\u3002\u4E0D\u8981\u5BB3\u6015\uFF0C\u6216\u662F\u62C5\u5FE7\u81EA\u5DF1\u4F3C\u4E4E\u8BFB\u5F97\u5F88\u80A4\u6D45\u3002\u5C31\u7B97\u662F\u6700\u96BE\u8BFB\u7684\u4E66\u4E5F\u5FEB\u5FEB\u5730\u8BFB\u4E00\u904D\u3002\u5F53\u4F60\u518D\u8BFB\u7B2C\u4E8C\u6B21\u65F6\uFF0C\u4F60\u5C31\u5DF2\u7ECF\u51C6\u5907\u597D\u8981\u8BFB\u8FD9\u672C\u4E66\u4E86\u3002</p><h2 id="\u7B2C\u4E94\u7AE0-\u5982\u4F55\u505A\u4E00\u4E2A\u81EA\u6211\u8981\u6C42\u7684\u8BFB\u8005" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u4E94\u7AE0-\u5982\u4F55\u505A\u4E00\u4E2A\u81EA\u6211\u8981\u6C42\u7684\u8BFB\u8005" aria-hidden="true">#</a> \u7B2C\u4E94\u7AE0 \u5982\u4F55\u505A\u4E00\u4E2A\u81EA\u6211\u8981\u6C42\u7684\u8BFB\u8005</h2><p>\u53EA\u8981\u662F\u8D85\u8D8A\u57FA\u7840\u9605\u8BFB\u7684\u9605\u8BFB\u5C42\u6B21\uFF0C\u9605\u8BFB\u7684\u827A\u672F\u5C31\u662F\u8981\u4EE5\u9002\u5F53\u7684\u987A\u5E8F\u63D0\u51FA\u9002\u5F53\u7684\u95EE\u9898\u3002\u5173\u4E8E\u4E00\u672C\u4E66\uFF0C\u4F60\u4E00\u5B9A\u8981\u63D0\u51FA\u56DB\u4E2A\u4E3B\u8981\u7684\u95EE\u9898\uFF1A</p><ol><li>\u6574\u4F53\u6765\u8BF4\uFF0C\u8FD9\u672C\u4E66\u5230\u5E95\u5728\u8C08\u4E9B\u4EC0\u4E48\uFF1F\u4F60\u4E00\u5B9A\u8981\u60F3\u529E\u6CD5\u627E\u51FA\u8FD9\u672C\u4E66\u7684\u4E3B\u9898\uFF0C\u4F5C\u8005\u5982\u4F55\u4F9D\u6B21\u53D1\u5C55\u8FD9\u4E2A\u4E3B\u9898\uFF0C\u5982\u4F55\u9010\u6B65\u4ECE\u6838\u5FC3\u4E3B\u9898\u5206\u89E3\u51FA\u4ECE\u5C5E\u7684\u5173\u952E\u8BAE\u9898\u6765\u3002</li><li>\u4F5C\u8005\u7EC6\u90E8\u8BF4\u4E86\u4EC0\u4E48\uFF0C\u600E\u4E48\u8BF4\u7684\uFF1F\u4F60\u4E00\u5B9A\u8981\u60F3\u529E\u6CD5\u627E\u51FA\u4E3B\u8981\u7684\u60F3\u6CD5\u3001\u58F0\u660E\u4E0E\u8BBA\u70B9\u3002\u8FD9\u4E9B\u7EC4\u5408\u6210\u4F5C\u8005\u60F3\u8981\u4F20\u8FBE\u7684\u7279\u6B8A\u8BAF\u606F\u3002</li><li>\u8FD9\u672C\u4E66\u8BF4\u5F97\u6709\u9053\u7406\u5417\uFF1F\u662F\u5168\u90E8\u6709\u9053\u7406\uFF0C\u8FD8\u662F\u90E8\u5206\u6709\u9053\u7406\uFF1F\u9664\u975E\u4F60\u80FD\u56DE\u7B54\u524D\u4E24\u4E2A\u95EE\u9898\uFF0C\u5426\u5219\u4F60\u6CA1\u6CD5\u56DE\u7B54\u8FD9\u4E2A\u95EE\u9898\u3002\u5728\u4F60\u5224\u65AD\u8FD9\u672C\u4E66\u662F\u5426\u6709\u9053\u7406\u4E4B\u524D\uFF0C\u4F60\u5FC5\u987B\u5148\u4E86\u89E3\u6574\u672C\u4E66\u5728\u8BF4\u4E9B\u4EC0\u4E48\u624D\u884C\u3002\u7136\u800C\uFF0C\u7B49\u4F60\u4E86\u89E3\u4E86\u4E00\u672C\u4E66\uFF0C\u5982\u679C\u4F60\u53C8\u8BFB\u5F97\u5F88\u8BA4\u771F\u7684\u8BDD\uFF0C\u4F60\u4F1A\u89C9\u5F97\u6709\u8D23\u4EFB\u4E3A\u8FD9\u672C\u4E66\u505A\u4E2A\u81EA\u5DF1\u7684\u5224\u65AD\u3002\u5149\u662F\u77E5\u9053\u4F5C\u8005\u7684\u60F3\u6CD5\u662F\u4E0D\u591F\u7684\u3002</li><li>\u8FD9\u672C\u4E66\u8DDF\u4F60\u6709\u4EC0\u4E48\u5173\u7CFB\uFF1F\u5982\u679C\u8FD9\u672C\u4E66\u7ED9\u4E86\u4F60\u4E00\u4E9B\u8D44\u8BAF\uFF0C\u4F60\u4E00\u5B9A\u8981\u95EE\u95EE\u8FD9\u4E9B\u8D44\u8BAF\u6709\u4EC0\u4E48\u610F\u4E49\u3002\u4E3A\u4EC0\u4E48\u8FD9\u4F4D\u4F5C\u8005\u4F1A\u8BA4\u4E3A\u77E5\u9053\u8FD9\u4EF6\u4E8B\u5F88\u91CD\u8981\uFF1F\u4F60\u771F\u7684\u6709\u5FC5\u8981\u53BB\u4E86\u89E3\u5417\uFF1F\u5982\u679C\u8FD9\u672C\u4E66\u4E0D\u53EA\u63D0\u4F9B\u4E86\u8D44\u8BAF\uFF0C\u8FD8\u542F\u53D1\u4E86\u4F60\uFF0C\u5C31\u66F4\u6709\u5FC5\u8981\u627E\u51FA\u5176\u4ED6\u76F8\u5173\u7684\u3001\u66F4\u6DF1\u7684\u542B\u610F\u6216\u5EFA\u8BAE\uFF0C\u4EE5\u83B7\u5F97\u66F4\u591A\u7684\u542F\u793A\u3002</li></ol><p><strong>\u5982\u4F55\u8BA9\u4E00\u672C\u4E66\u771F\u6B63\u5C5E\u4E8E\u81EA\u5DF1</strong></p><p>\u8BFB\u51FA\u8A00\u5916\u4E4B\u610F\uFF0C\u5199\u4E0B\u6765\u3002\u5728\u4E66\u4E0A\u505A\u7B14\u8BB0\uFF0C\u5176\u5B9E\u5C31\u662F\u5728\u8868\u8FBE\u4F60\u8DDF\u4F5C\u8005\u4E4B\u95F4\u76F8\u5F02\u6216\u76F8\u540C\u7684\u89C2\u70B9\u3002\u8FD9\u662F\u4F60\u5BF9\u4F5C\u8005\u6240\u80FD\u4ED8\u51FA\u7684\u6700\u9AD8\u7684\u656C\u610F\u3002</p><p><strong>\u505A\u7B14\u8BB0\u7684\u65B9\u6CD5</strong></p><p>\u5728\u68C0\u89C6\u9605\u8BFB\u4E2D\uFF0C\u8981\u56DE\u7B54\u7684\u95EE\u9898\u662F\uFF1A\u7B2C\u4E00\uFF0C\u8FD9\u662F\u4EC0\u4E48\u6837\u7684\u4E00\u672C\u4E66\uFF1F\u7B2C\u4E8C\uFF0C\u6574\u672C\u4E66\u5728\u8C08\u7684\u662F\u4EC0\u4E48\uFF1F\u7B2C\u4E09\uFF0C\u4F5C\u8005\u662F\u501F\u7740\u600E\u6837\u7684\u6574\u4F53\u67B6\u6784\uFF0C\u6765\u53D1\u5C55\u4ED6\u7684\u89C2\u70B9\u6216\u9648\u8FF0\u4ED6\u5BF9\u8FD9\u4E2A\u4E3B\u9898\u7684\u7406\u89E3\uFF1F\u4F60\u5E94\u8BE5\u505A\u4E00\u4E0B\u7B14\u8BB0\uFF0C\u628A\u8FD9\u4E9B\u95EE\u9898\u7684\u7B54\u6848\u5199\u4E0B\u6765\u3002\u5C24\u5176\u5982\u679C\u4F60\u77E5\u9053\u7EC8\u6709\u4E00\u5929\uFF0C\u6216\u8BB8\u662F\u51E0\u5929\u6216\u51E0\u4E2A\u6708\u4E4B\u540E\uFF0C\u4F60\u4F1A\u91CD\u65B0\u62FF\u8D77\u8FD9\u672C\u4E66\u505A\u5206\u6790\u9605\u8BFB\u65F6\uFF0C\u5C31\u66F4\u8BE5\u5C06\u95EE\u9898\u4E0E\u7B54\u6848\u5148\u5199\u4E0B\u6765\u3002\u8FD9\u4E9B\u7B14\u8BB0\u4E3B\u8981\u7684\u91CD\u70B9\u662F\u5168\u4E66\u7684\u67B6\u6784\uFF0C\u800C\u4E0D\u662F\u5185\u5BB9\u2014\u2014\u81F3\u5C11\u4E0D\u662F\u7EC6\u8282\u3002\u56E0\u6B64\u6211\u4EEC\u79F0\u8FD9\u6837\u7684\u7B14\u8BB0\u4E3A\u7ED3\u6784\u7B14\u8BB0\uFF08structural note-making\uFF09\u3002</p><p>\u6982\u5FF5\u7B14\u8BB0\uFF08conceptual note-making\uFF09\uFF0C\u8FD9\u4E9B\u6982\u5FF5\u662F\u4F5C\u8005\u7684\u89C2\u70B9\uFF0C\u800C\u5F53\u4F60\u8BFB\u5F97\u8D8A\u6DF1\u8D8A\u5E7F\u65F6\uFF0C\u4FBF\u4E5F\u4F1A\u51FA\u73B0\u4F60\u81EA\u5DF1\u7684\u89C2\u70B9\u4E86\u3002</p><p>\u8FA9\u8BC1\u7B14\u8BB0\uFF08dialectical note-making\uFF09\uFF0C\u5BF9\u4E00\u4E2A\u5DF2\u7ECF\u719F\u7EC3\u540C\u65F6\u8BFB\u597D\u51E0\u672C\u76F8\u540C\u4E3B\u9898\u4E66\u7C4D\u7684\u4E13\u4E1A\u9605\u8BFB\u8005\u6765\u8BF4\uFF0C\u8FD8\u6709\u4E00\u4E2A\u66F4\u9AD8\u5C42\u6B21\u7684\u8BB0\u7B14\u8BB0\u7684\u65B9\u6CD5\u3002\u90A3\u5C31\u662F\u9488\u5BF9\u4E00\u573A\u8BA8\u8BBA\u60C5\u5883\u7684\u7B14\u8BB0\u3002</p><h2 id="\u7B2C\u516D\u7AE0-\u4E00\u672C\u4E66\u7684\u5206\u7C7B" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u516D\u7AE0-\u4E00\u672C\u4E66\u7684\u5206\u7C7B" aria-hidden="true">#</a> \u7B2C\u516D\u7AE0 \u4E00\u672C\u4E66\u7684\u5206\u7C7B</h2><p><strong>\u4E66\u7C4D\u5206\u7C7B\u7684\u91CD\u8981\u6027</strong></p><p><strong>\u4ECE\u4E00\u672C\u4E66\u7684\u4E66\u540D\u4E2D\u4F60\u80FD\u5B66\u5230\u4EC0\u4E48</strong></p><p><strong>\u5B9E\u7528\u6027 vs. \u7406\u8BBA\u6027\u4F5C\u54C1</strong></p><h2 id="\u7B2C\u4E03\u7AE0-\u900F\u89C6\u4E00\u672C\u4E66" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u4E03\u7AE0-\u900F\u89C6\u4E00\u672C\u4E66" aria-hidden="true">#</a> \u7B2C\u4E03\u7AE0 \u900F\u89C6\u4E00\u672C\u4E66</h2><p><strong>\u7ED3\u6784\u4E0E\u89C4\u5212\uFF1A\u53D9\u8FF0\u6574\u672C\u4E66\u7684\u5927\u610F</strong></p><p><strong>\u9A7E\u9A6D\u590D\u6742\u7684\u5185\u5BB9\uFF1A\u4E3A\u4E00\u672C\u4E66\u62DF\u5927\u7EB2\u7684\u6280\u5DE7</strong></p><p>\u5C06\u5185\u5BB9\u5927\u7EB2\u6392\u5217\u5982\u4E0B\uFF1A\uFF081\uFF09\u4F5C\u8005\u5C06\u5168\u4E66\u5206\u6210\u4E94\u4E2A\u90E8\u5206\uFF0C\u7B2C\u4E00\u90E8\u5206\u8C08\u7684\u662F\u4EC0\u4E48\uFF0C\u7B2C\u4E8C\u90E8\u5206\u8C08\u7684\u662F\u4EC0\u4E48\uFF0C\u7B2C\u4E09\u90E8\u5206\u8C08\u7684\u662F\u522B\u7684\u4E8B\uFF0C\u7B2C\u56DB\u90E8\u5206\u5219\u662F\u53E6\u5916\u7684\u89C2\u70B9\uFF0C\u7B2C\u4E94\u90E8\u5206\u53C8\u662F\u53E6\u4E00\u4E9B\u4E8B\u3002\uFF082\uFF09\u7B2C\u4E00\u4E2A\u4E3B\u8981\u7684\u90E8\u5206\u53C8\u5206\u6210\u4E09\u4E2A\u6BB5\u843D\uFF0C\u7B2C\u4E00\u6BB5\u843D\u4E3A X\uFF0C\u7B2C\u4E8C\u6BB5\u843D\u4E3A Y\uFF0C\u7B2C\u4E09\u6BB5\u843D\u4E3A Z\u3002\uFF083\uFF09\u5728\u7B2C\u4E00\u90E8\u5206\u7684\u7B2C\u4E00\u9636\u6BB5\uFF0C\u4F5C\u8005\u6709\u56DB\u4E2A\u91CD\u70B9\uFF0C\u7B2C\u4E00\u4E2A\u91CD\u70B9\u662F A\uFF0C\u7B2C\u4E8C\u4E2A\u91CD\u70B9\u662F B\uFF0C\u7B2C\u4E09\u4E2A\u91CD\u70B9\u662F C\uFF0C\u7B2C\u56DB\u4E2A\u91CD\u70B9\u662F D \u7B49\u7B49\u3002</p><p><strong>\u9605\u8BFB\u4E0E\u5199\u4F5C\u7684\u4E92\u60E0\u6280\u5DE7</strong></p><p><strong>\u53D1\u73B0\u4F5C\u8005\u7684\u610F\u56FE</strong></p><p>\u627E\u51FA\u4F5C\u8005\u8981\u95EE\u7684\u95EE\u9898</p><p><strong>\u5206\u6790\u9605\u8BFB\u7684\u7B2C\u4E00\u4E2A\u9636\u6BB5</strong></p><p>\u627E\u51FA\u4E00\u672C\u4E66\u5728\u8C08\u4E9B\u4EC0\u4E48\u7684\u56DB\u4E2A\u89C4\u5219</p><ol><li>\u4F9D\u7167\u4E66\u672C\u7684\u79CD\u7C7B\u4E0E\u4E3B\u9898\u4F5C\u5206\u7C7B</li><li>\u7528\u6700\u7B80\u77ED\u7684\u53E5\u5B50\u8BF4\u51FA\u6574\u672C\u4E66\u5728\u8C08\u4E9B\u4EC0\u4E48</li><li>\u6309\u7167\u987A\u5E8F\u5173\u7CFB\uFF0C\u5217\u51FA\u5168\u4E66\u7684\u91CD\u8981\u90E8\u5206\u3002\u5C06\u5168\u4E66\u7684\u7EB2\u8981\u62DF\u51FA\u6765\u4E4B\u540E\uFF0C\u518D\u5C06\u5404\u4E2A\u90E8\u95E8\u7684\u7EB2\u8981\u4E5F\u4E00\u4E00\u5217\u51FA</li><li>\u627E\u51FA\u4F5C\u8005\u8981\u95EE\u7684\u95EE\u9898\uFF0C\u6216\u4F5C\u8005\u60F3\u8981\u89E3\u51B3\u7684\u95EE\u9898</li></ol><h2 id="\u7B2C\u516B\u7AE0-\u4E0E\u4F5C\u8005\u627E\u51FA\u5171\u901A\u7684\u8BCD\u4E49" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u516B\u7AE0-\u4E0E\u4F5C\u8005\u627E\u51FA\u5171\u901A\u7684\u8BCD\u4E49" aria-hidden="true">#</a> \u7B2C\u516B\u7AE0 \u4E0E\u4F5C\u8005\u627E\u51FA\u5171\u901A\u7684\u8BCD\u4E49</h2>',61);function n(e,t){return i}var s=r(p,[["render",n],["__file","\u5982\u4F55\u9605\u8BFB\u4E00\u672C\u4E66.html.vue"]]);export{s as default};
